	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatter.Format(tc.plan, &schemarepo.Schemas{})
			if diff := cmp.Diff(tc.want, got); diff != "" {
				t.Errorf("Format() mismatch (-want +got):\n%s", diff)
			}
		})
	}
}

func TestCompactDiffFormatter_Sorting(t *testing.T) {
	// Test that resources are sorted within their action groups
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "zebra",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Create,
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "apple",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Create,
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "middle",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Create,
					DeposedKey: states.NotDeposed,
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	got := formatter.Format(plan, &schemarepo.Schemas{})

	// Verify that apple comes before middle, which comes before zebra
	appleIdx := strings.Index(got, "aws_instance.apple")
	middleIdx := strings.Index(got, "aws_instance.middle")
	zebraIdx := strings.Index(got, "aws_instance.zebra")

	if appleIdx == -1 || middleIdx == -1 || zebraIdx == -1 {
		t.Fatalf("Expected all resources to be in output: %s", got)
	}

	if appleIdx > middleIdx || middleIdx > zebraIdx {
		t.Errorf("Resources not sorted correctly. got:\n%s", got)
	}
}

func TestCompactDiffFormatter_DeposedResources(t *testing.T) {
	// Test that deposed resources are skipped
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "example",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Create,
					DeposedKey: states.NotDeposed,
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "deposed",
							},
							Key: addrs.NoKey,
						},
					},
					Action:     plans.Delete,
					DeposedKey: states.DeposedKey("0000000000000001"), // non-NotDeposed
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	got := formatter.Format(plan, &schemarepo.Schemas{})

	// Verify that deposed resource is not in output
	if strings.Contains(got, "aws_instance.deposed") {
		t.Errorf("Deposed resource should not appear in output:\n%s", got)
	}

	// Verify that non-deposed resource is in output
	if !strings.Contains(got, "aws_instance.example") {
		t.Errorf("Non-deposed resource should appear in output:\n%s", got)
	}
}

