  <- data.aws_ami.ubuntu

Summary:
  Create:  0
  Update:  0
  Replace: 0
  Delete:  0
  Read:    1
  Forget:  0
`,
		},
		"forget action": {
			plan: &plans.Plan{
				Changes: &plans.ChangesSrc{
					Resources: []*plans.ResourceInstanceChangeSrc{
						{
							Addr: addrs.AbsResourceInstance{
